-- Maximum argument value length (bytes)
local MAX_ARG_LENGTH = 1024 * 64  -- 64KB per argument
-- Maximum key length
local MAX_KEY_LENGTH = 512

-- Helper: send JSON response
local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.header["X-Content-Type-Options"] = "nosniff"
    ngx.say(cjson.encode(data))
    ngx.exit(status)
end

-- Helper: send error response
local function send_error(status, message)
    send_json_response(status, { success = false, error = message })
end

-- Validate and sanitize a single argument
local function validate_argument(arg, index, command)
    if type(arg) ~= "string" and type(arg) ~= "number" then
        return nil, string.format("Argument %d must be a string or number", index)
    end

    local str_arg = tostring(arg)

    -- Check argument length
    if #str_arg > MAX_ARG_LENGTH then
        return nil, string.format("Argument %d exceeds maximum length of %d bytes", index, MAX_ARG_LENGTH)
    end

    -- For key arguments (typically first arg for most commands), enforce key length
    if index == 1 and command ~= "MGET" and command ~= "MSET" and command ~= "DEL" then
        if #str_arg > MAX_KEY_LENGTH then
            return nil, string.format("Key length exceeds maximum of %d bytes", MAX_KEY_LENGTH)
        end
    end

    -- Reject null bytes which could cause issues
    if string.find(str_arg, "\0") then
        return nil, string.format("Argument %d contains null bytes", index)
    end

    return str_arg, nil
end

-- Validate the command name
local function validate_command(cmd)
    if type(cmd) ~= "string" then
        return nil, "Command must be a string"
    end

    -- Normalize to uppercase
    local upper_cmd = string.upper(cmd)

    -- Strip any whitespace
    upper_cmd = string.match(upper_cmd, "^%s*(.-)%s*$")

    -- Only allow alphanumeric command names
    if not string.match(upper_cmd, "^[A-Z]+$") then
        return nil, "Invalid command format: only alphabetic characters allowed"
    end

    -- Check blocked list first
    if BLOCKED_COMMANDS[upper_cmd] then
        return nil, string.format("Command '%s' is blocked for security reasons", upper_cmd)
    end

    -- Check whitelist
    if not ALLOWED_COMMANDS[upper_cmd] then
        return nil, string.format("Command '%s' is not in the allowed commands list", upper_cmd)
    end

    return upper_cmd, nil
end

-- Parse request body or query parameters
local function parse_request()
    local method = ngx.req.get_method()

    if method == "POST" or method == "PUT" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()

        if not body then
            return nil, "Empty request body"
        end

        local ok, data = pcall(cjson.decode, body)
        if not ok then
            return nil, "Invalid JSON in request body"
        end

        return data, nil

    elseif method == "GET" then
        local args = ngx.req.get_uri_args()
        local command = args.command or args.cmd
        local params = args.args

        if not command then
            return nil, "Missing 'command' or 'cmd' parameter"
        end

        local parsed_args = {}
        if params then
            if type(params) == "table" then
                parsed_args = params
            else
                -- Split comma-separated args, but also support multiple 'args' params
                for part in string.gmatch(params, "[^,]+") do
                    local trimmed = string.match(part, "^%s*(.-)%s*$")
                    if trimmed and #trimmed > 0 then
                        table.insert(parsed_args, trimmed)
                    end
                end
            end
        end

        return { command = command, args = parsed_args }, nil
    else
        return nil, "Only GET and POST methods are supported"
    end
end

-- Connect to Redis
local function connect_redis()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "Failed to connect to Redis: " .. (err or "unknown error")
    end

    if REDIS_PASSWORD and REDIS_PASSWORD ~= "" then
        local res, auth_err = red:auth(REDIS_PASSWORD)
        if not res then
            red:close()
            return nil, "Redis authentication failed: " .. (auth_err or "unknown error")
        end
    end

    return red, nil
end

-- Return Redis connection to pool
local function keepalive_redis(red)
    if red then
        local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
        if not ok then
            ngx.log(ngx.WARN, "Failed to set Redis keepalive: ", err)
            red:close()
        end
    end
end

-- Format Redis response for JSON output
local function format_response(res)
    if res == ngx.null then
        return cjson.null
    end

    if type(res) == "table" then
        local formatted = {}
        for i, v in ipairs(res) do
            if v == ngx.null then
                formatted[i] = cjson.null
            elseif type(v) == "table" then
                formatted[i] = format_response(v)
            else
                formatted[i] = v
            end
        end
        return formatted
    end

    return res
end

-- Execute a single Redis command
local function execute_command(red, command, args)
    -- Validate command
    local validated_cmd, cmd_err = validate_command(command)
    if not validated_cmd then
        return nil, cmd_err
    end

    -- Validate arguments
    local cmd_spec = ALLOWED_COMMANDS[validated_cmd]
    local validated_args = {}

    if args and type(args) == "table" then
        -- Check argument count
        local arg_count = #args
        if arg_count < cmd_spec.min_args then
            return nil, string.format(
                "Command '%s' requires at least %d argument(s), got %d",
                validated_cmd, cmd_spec.min_args, arg_count
            )
        end
        if arg_count > cmd_spec.max_args then
            return nil, string.format(
                "Command '%s' accepts at most %d argument(s), got %d",
                validated_cmd, cmd_spec.max_args, arg_count
            )
        end

        for i, arg in ipairs(args) do
            local validated_arg, arg_err = validate_argument(arg, i, validated_cmd)
            if not validated_arg then
                return nil, arg_err
            end
            table.insert(validated_args, validated_arg)
        end
    else
        if cmd_spec.min_args > 0 then
            return nil, string.format(
                "Command '%s' requires at least %d argument(s)",
                validated_cmd, cmd_spec.min_args
            )
        end
    end

    -- Get the Redis method (lowercase)
    local redis_method = string.lower(validated_cmd)
    local func = red[redis_method]

    if not func then
        return nil, string.format("Redis method '%s' not available", redis_method)
    end

    -- Execute the command
    local res, err
    if #validated_args == 0 then
        res, err = func(red)
    else
        res, err = func(red, unpack(validated_args))
    end

    if not res then
        return nil, "Redis command failed: " .. (err or "unknown error")
    end

    return format_response(res), nil
end

-- Rate limiting using Redis (simple token bucket per IP)
local function check_rate_limit(red, client_ip)
    local rate_limit_key = "ratelimit:redis_api:" .. client_ip
    local max_requests = 100  -- per window
    local window_seconds = 60

    local current, err = red:incr(rate_limit_key)
    if not current then
        ngx.log(ngx.WARN, "Rate limit check failed: ", err)
        return true  -- allow on error
    end

    if current == 1 then
        red:expire(rate_limit_key, window_seconds)
    end

    if tonumber(current) > max_requests then
        return false
    end

    return true
end

-- Main handler
local function main()
    -- Only allow specific methods
    local method = ngx.req.get_method()
    if method ~= "GET" and method ~= "POST" then
        send_error(405, "Method not allowed")
        return
    end

    -- Parse request
    local request_data, parse_err = parse_request()
    if not request_data then
        send_error(400, parse_err)
        return
    end

    -- Connect to Redis
    local red, conn_err = connect_redis()
    if not red then
        send_error(503, conn_err)
        return
    end

    -- Rate limiting
    local client_ip = ngx.var.remote_addr or "unknown"
    local allowed = check_rate_limit(red, client_ip)
    if not allowed then
        keepalive_redis(red)
        send_error(429, "Rate limit exceeded. Please try again later.")
        return
    end

    -- Check if this is a batch request
    if request_data.commands and type(request_data.commands) == "table" then
        -- Batch mode: execute multiple commands
        local max_batch_size = 50
        if #request_data.commands > max_batch_size then
            keepalive_redis(red)
            send_error(400, string.format("Batch size exceeds maximum of %d commands", max_batch_size))
            return
        end

        local results = {}
        for i, cmd_entry in ipairs(request_data.commands) do
            if type(cmd_entry) ~= "table" then
                keepalive_redis(red)
                send_error(400, string.format("Command entry %d must be an object", i))
                return
            end

            local cmd = cmd_entry.command or cmd_entry.cmd
            local cmd_args = cmd_entry.args or {}

            if not cmd then
                keepalive_redis(red)
                send_error(400, string.format("Command entry %d is missing 'command' field", i))
                return
            end

            local result, exec_err = execute_command(red, cmd, cmd_args)
            if exec_err then
                table.insert(results, {
                    index = i,
                    success = false,
                    error = exec_err,
                    command = cmd
                })
            else
                table.insert(results, {
                    index = i,
                    success = true,
                    result = result,
                    command = string.upper(cmd)
                })
            end
        end

        keepalive_redis(red)
        send_json_response(200, {
            success = true,
            batch = true,
            count = #results,
            results = results
        })
        return
    end

    -- Single command mode
    local command = request_data.command or request_data.cmd
    if not command then
        keepalive_redis(red)
        send_error(400, "Missing 'command' field")
        return
    end

    local args = request_data.args or {}
    if type(args) ~= "table" then
        keepalive_redis(red)
        send_error(400, "'args' must be an array")
        return
    end

    local result, exec_err = execute_command(red, command, args)
    keepalive_redis(red)

    if exec_err then
        send_error(400, exec_err)
        return
    end

    send_json_response(200, {
        success = true,
        command = string.upper(command),
        result = result
    })
end

-- Execute main handler
main()